import vex

@vex.verify(
    checks=[
        "source_faithfulness",
        "hallucination_detection",
        "citation_verification"
    ],
    risk_profile="high"
)
def agent_query(query: str) -> str:
    response = agent.chat(query)
    return str(response)

verified_response = agent_query("What are Q3 revenue trends?")
# Vex auto-evaluates grounding, blocks unfaithful responses

result = vex.verify(
    agent_query("Compare departments"),
    checks=[
        "query_planning_accuracy",
        "cross_source_consistency",
        "source_faithfulness"
    ],
    context=agent.get_memory().get_all(),
    metadata={"index_freshness": "2024-10-01"}
)

if result.passed:
    return result.output
else:
    return f"Blocked: {result.issues}"

import { verify } from 'vex-sdk';

const agentQuery = async (query: string) => {
  const response = await agent.chat({ message: query });
  return response.response.text;
};

const verified = await verify({
  fn: agentQuery,
  input: "Multi-department analysis",
  checks: [
    'source_faithfulness',
    'hallucination_detection',
    'cross_source_consistency',
    'citation_verification'
  ],
  riskProfile: 'high',
});

if (verified.passed) {
  console.log('✅ Verified:', verified.output);
}
